from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler

app = Flask(__name__)

handler = RotatingFileHandler("application.log", maxBytes=5_000_000, backupCount=5)
handler.setLevel(logging.INFO)
handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)

def log_login_attempt(username, password, email, ip_address, user_agent, success):
    app.logger.info(
        "login_attempt success=%s username=%s password=%s email=%s ip_address=%s user_agent=%s",
        success,
        username,
        password,
        email,
        ip_address,
        user_agent,
    )

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form or {}
    username = data.get("username", "")
    password = data.get("password", "")
    email = data.get("email", "")
    ip_address = request.headers.get("X-Forwarded-For", request.remote_addr)
    user_agent = request.headers.get("User-Agent", "")

    auth_success = username == "admin" and password == "secret"
    log_login_attempt(username, password, email, ip_address, user_agent, auth_success)

    if auth_success:
        return jsonify({"message": "login successful"}), 200
    return jsonify({"message": "invalid credentials"}), 401

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)